import React, { useEffect, useState } from "react";

const AnadirPropietario = () => {
  const [empresas, setEmpresas] = useState([]);
  const [formulario, setFormulario] = useState({
    empresa: "",
    nombre: "",
    apellidoPaterno: "",
    apellidoMaterno: "",
    nacionalidad: "",
    fechaInicio: "",
    fechaFin: "",
  });

  // Simulación de llamada a base de datos (reemplazar con fetch real)
  useEffect(() => {
    const obtenerEmpresas = async () => {
      //cambiar por base de datos
      const datos = await Promise.resolve([
        { id: 1, nombre: "Empresa 1" },
        { id: 2, nombre: "Empresa 2" },
        { id: 3, nombre: "Empresa 3" },
      ]);
      setEmpresas(datos);
    };

    obtenerEmpresas();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormulario({ ...formulario, [name]: value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Aquí se puede hacer un POST al backend
    console.log("Datos del propietario:", formulario);
    alert("Propietario registrado correctamente");
  };

  return (
    <div className="p-4">
      <h2 className="text-2xl font-bold mb-4">Añadir Propietario</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block font-medium">Empresa</label>
          <select
            name="empresa"
            value={formulario.empresa}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
            required
          >
            <option value="">Seleccione una empresa</option>
            {empresas.map((empresa) => (
              <option key={empresa.id} value={empresa.nombre}>
                {empresa.nombre}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label className="block font-medium">Nombre</label>
          <input
            type="text"
            name="nombre"
            value={formulario.nombre}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
            required
          />
        </div>

        <div>
          <label className="block font-medium">Apellido Paterno</label>
          <input
            type="text"
            name="apellidoPaterno"
            value={formulario.apellidoPaterno}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
            required
          />
        </div>

        <div>
          <label className="block font-medium">Apellido Materno</label>
          <input
            type="text"
            name="apellidoMaterno"
            value={formulario.apellidoMaterno}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
          />
        </div>

        <div>
          <label className="block font-medium">Nacionalidad</label>
          <input
            type="text"
            name="nacionalidad"
            value={formulario.nacionalidad}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
          />
        </div>

        <div>
          <label className="block font-medium">Fecha de Inicio</label>
          <input
            type="date"
            name="fechaInicio"
            value={formulario.fechaInicio}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
          />
        </div>

        <div>
          <label className="block font-medium">Fecha de Fin</label>
          <input
            type="date"
            name="fechaFin"
            value={formulario.fechaFin}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
          />
        </div>

        <button
          type="submit"
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          Guardar Propietario
        </button>
      </form>
    </div>
  );
};

export default AnadirPropietario;
